-- Edifikana local-dev seed data
-- Issue: https://github.com/CodeHavenX/MonoRepo/issues/401
--
-- Apply with:  ./scripts/edifikana_seed_test_data.sh  (from repo root)
-- This runs `supabase db reset` which wipes the DB and re-applies all
-- migrations + this file from scratch.
--
-- All seeded users share the password: SeedUser2024!
-- This is an intentionally public dev-only credential for local instances.
--
-- UUID key:
--   auth/app users  : 00000000-0000-0000-0003-xxxxxxxxxxxx
--   organizations   : 00000000-0000-0000-0001-xxxxxxxxxxxx
--   properties      : 00000000-0000-0000-0002-xxxxxxxxxxxx
--   units           : 00000000-0000-0000-0004-xxxxxxxxxxxx
--   employees       : 00000000-0000-0000-0005-xxxxxxxxxxxx
-- =============================================================================

-- pgcrypto for bcrypt password hashing
CREATE EXTENSION IF NOT EXISTS pgcrypto;

